
  const RESUME_B64 = "";
  const resumeHref = "data:application/pdf;base64," + RESUME_B64;
  document.getElementById('downloadBtn').href = resumeHref;
  document.getElementById('downloadBtn2').href = resumeHref;

  // theme toggle
  const body = document.body;
  const toggle = document.getElementById('themeToggle');
  const themeLabel = document.getElementById('themeLabel');
  toggle.addEventListener('click', (e) => {
    const btn = e.target.closest('button');
    if(!btn) return;
    const mode = btn.dataset.mode;
    body.setAttribute('data-theme', mode);
    toggle.querySelectorAll('button').forEach(b => b.classList.toggle('on', b === btn));
    themeLabel.textContent = 'mode: ' + mode;
  });

  // mobile nav
  const burger = document.getElementById('burger');
  const navLinks = document.getElementById('navLinks');
  burger.addEventListener('click', () => navLinks.classList.toggle('open'));
  navLinks.querySelectorAll('a').forEach(a => a.addEventListener('click', () => navLinks.classList.remove('open')));

  // active link on scroll
  const sections = document.querySelectorAll('section[id]');
  const navA = document.querySelectorAll('.nav-a');
  const navObserver = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if(entry.isIntersecting){
        navA.forEach(a => a.classList.toggle('active', a.getAttribute('href') === '#' + entry.target.id));
      }
    });
  }, { rootMargin: '-40% 0px -50% 0px' });
  sections.forEach(s => navObserver.observe(s));

  // reveal on scroll
  const revealObserver = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if(entry.isIntersecting){ entry.target.classList.add('in-view'); revealObserver.unobserve(entry.target); }
    });
  }, { threshold: 0.15 });
  document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));

  // contact form (demo — no backend)
  const form = document.getElementById('contactForm');
  const sendStatus = document.getElementById('sendStatus');
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    sendStatus.textContent = "Message ready — connect a backend or mailto action to actually send it.";
    form.reset();
  });
/* ===========================
      Typing Animation
=========================== */

const words = [
    "Frontend Developer",
    "Web Designer",
    "UI Developer",
    "JavaScript Enthusiast"
];

let wordIndex = 0;
let charIndex = 0;
let deleting = false;

const typing = document.getElementById("typing");

function typeEffect(){

    if(!typing) return;

    const current = words[wordIndex];

    if(!deleting){

        typing.textContent = current.substring(0,charIndex++);

        if(charIndex > current.length){

            deleting = true;

            setTimeout(typeEffect,1500);

            return;
        }

    }

    else{

        typing.textContent = current.substring(0,charIndex--);

        if(charIndex < 0){

            deleting = false;

            wordIndex = (wordIndex+1)%words.length;

        }

    }

    setTimeout(typeEffect,deleting?60:120);

}

typeEffect();

/* ===========================
      Hero Mouse Parallax
=========================== */

const circles = document.querySelectorAll(".hero-bg span");

document.addEventListener("mousemove",(e)=>{

    const x = (e.clientX/window.innerWidth)-0.5;
    const y = (e.clientY/window.innerHeight)-0.5;

    circles.forEach((circle,index)=>{

        const speed=(index+1)*12;

        circle.style.transform=
        `translate(${x*speed}px,${y*speed}px)`;

    });

});